from typing import NamedTuple

import procfunc as pf
from procfunc.nodes import types as t

from infinigen_v2.generators.util.curve import curve_to_noncyclic, fillet_mask


@pf.nodes.node_function
def rectangle_outline(
    vector: t.SocketOrVal[pf.Vector],
) -> pf.ProcNode:
    # Code generated by procfunc v0.16.0

    curve_quadrilateral = pf.nodes.geo.curve_quadrilateral(
        width=vector.x, height=vector.y
    )

    transform = pf.nodes.geo.transform(
        geometry=curve_quadrilateral,
        translation=vector * (0.5, 0.5, 0.0),
    )
    return transform


class RoomEdgeCurveResult(NamedTuple):
    curve: pf.ProcNode
    is_flat_point: pf.ProcNode[bool]
    orig_point_idx: pf.ProcNode[int]


def room_edge_curve_distribution(
    rng: pf.RNG,
    dimensions: pf.Vector | None = None,
    vertices_x: int | None = None,
    vertices_y: int | None = None,
    corner_cutout_probability: float | None = None,
    fillet_probability: float | None = None,
    fillet_radius: float | None = None,
    fillet_count: int | None = None,
) -> RoomEdgeCurveResult:
    seed = pf.random.randint(rng, 0, 1000)

    if dimensions is None:
        dimensions = pf.random.uniform(rng, (3.0, 3.0, 2.0), (5, 5, 3))
        dimensions = pf.Vector(dimensions)

    if vertices_x is None:
        vertices_x = pf.random.randint(rng, 4, 5)
    if vertices_y is None:
        vertices_y = pf.random.randint(rng, 4, 5)
    if corner_cutout_probability is None:
        corner_cutout_probability = pf.random.uniform(rng, 0.0, 0.5)

    fillet_radius_opt = pf.random.uniform(rng, 0.15, 1) ** 2
    fillet_count_opt = pf.control.choice(rng, [(1, 0.5), (5, 0.5)])
    fillet_prob_opt = pf.random.uniform(rng, 0.1, 0.5)

    fillet_conf = pf.control.choice(
        rng,
        [
            ((0.0, 0.5, 2), 0.5),
            ((fillet_prob_opt, fillet_radius_opt, fillet_count_opt), 3),
        ],
    )
    if fillet_probability is None:
        fillet_probability = fillet_conf[0]
    if fillet_radius is None:
        fillet_radius = fillet_conf[1]
    if fillet_count is None:
        fillet_count = fillet_conf[2]

    rectangle_outline_result = rectangle_outline(vector=dimensions)

    curve_to_noncyclic_result = curve_to_noncyclic(input=rectangle_outline_result)

    fillet_selection = pf.nodes.func.random_boolean(
        probability=fillet_probability,
        seed=seed,
    )

    radius_same_or_different_seed = pf.control.choice(
        rng,
        [
            # every corner uses same seed or different seed for radius
            (0, 1),
            (pf.nodes.geo.input_index(), 1),
        ],
    )
    fillet_radius_result = pf.nodes.func.random_value(
        min=0.15,
        max=1.5,
        id=radius_same_or_different_seed,
        seed=seed,
    )
    fillet_mask_result = fillet_mask(
        geometry=curve_to_noncyclic_result,
        selection=fillet_selection,
        fillet_vertices=8,
        radius=fillet_radius_result,
    )

    return RoomEdgeCurveResult(
        curve=fillet_mask_result.curve,
        is_flat_point=fillet_mask_result.is_flat_point,
        orig_point_idx=fillet_mask_result.orig_point_idx,
    )
